function trackerFunc(send) {
  return function (e) {
    const el = e.target.closest(
      "a, button, li, div, span, svg, [role=button]"
    );
    if (!el) return;

    send({
      tag_code: "COMMON_CLICK",
      event_type: "click",
      click_text: el.innerText?.trim().slice(0, 30) || '',
      class_name: el.className || '',
      tag: el.tagName
    });
  }
}

function trackerFunc(send) {
  return function () {
    let prd_brand = '';
    let prd_code = '';
    let tab_name = '';
    let srch_kwd = '';

    if (
      location.pathname.match('product/detail') &&
      document.querySelector('.prod-item__display-name')
    ) {
      const prdel = document.querySelector('.prod-item__display-name').parentElement;
      prd_brand = prdel.querySelector('div > p')?.innerText || '';
      prd_code = location.href.split('/').pop();

    } else if (
      location.pathname.match('/search') &&
      document.querySelector('.search-result__tab')
    ) {
      tab_name =
        document.querySelector('button > div.is-selected > span')?.innerText || '';

      const inputEl = document.querySelector('.search-header__input');
      srch_kwd = inputEl?.value || inputEl?.placeholder || '';
    }

    setTimeout(() => {
      send({
        tag_code: "PV_DETAIL",
        event_type: "pageview",
        prd_code,
        prd_brand,
        tab_name,
        srch_kwd
      });
    }, 300);
  }
}

function func() {

  if (window.__pvTrackerInitialized) return;
  window.__pvTrackerInitialized = true;

  let lastTrackedUrl = null;
  let lastTrackedTime = 0;
  let initialUrl = location.href;
  const TRACK_DEBOUNCE_MS = 300;

  let didInitialLoadFire = false;
  var timeout;
  // 예외 처리할 URL 경로 목록
  const skipPaths = [
    // 커머스 - 상품 상세, 장바구니, 리뷰 상세보기, 주문&결제, 결제 실패, 찜, 브랜드스토어
    '/product/detail',
    '/order/cart',
    '/review/reviewdetail',
    '/favorite',
    '/store$',
    '/store/[^/]+$',
    // 휘슬 - 메인
    //'/whistle/main',
    // 뉴스 - 상세
    '/news/detail',
    // 마이페이지
    '/myPage$',
    'category/detail',
    '/order/payment',
  //  '/order/processing',
    "myPage/recentGoods",
    'myPage/review$',
    "exchange/main",
    "exchange/detail",
    "exchange/detail/complete",
    "exchange/complete",
    "/search",
    "main/exhibition",
    'v1/payments',
    'order/complete',
    'myPage/review/reviewerProfile',
    'news?'
  ];


  function shouldSkipTracking(url) {
    return skipPaths.some(path => url.match(path));
  }

  function sendPageView(url, source) {
      Ntm00002.Event.fireUserDefined("pv", { act_type: "pageview" });
  }

  function trackPageView(source) {
    const currentUrl = location.href;
    const now = Date.now();
    // console.log('NTH TEST pv trackPageView');
    if (shouldSkipTracking(currentUrl)) {
      lastTrackedUrl = currentUrl;
     // console.log('NTH pv TEST >> Skipped: shouldSkipTracking');
      return;
    }

    const isDuplicate =
      (currentUrl === lastTrackedUrl && source !== 'popstate') ||
      (currentUrl === initialUrl && !didInitialLoadFire) ||
      now - lastTrackedTime < TRACK_DEBOUNCE_MS;

    if (!isDuplicate) {
      lastTrackedUrl = currentUrl;
      lastTrackedTime = now;
      setTimeout(() => {
        sendPageView(currentUrl, source);
      }, 200);
    }
  }

  // 멀티 웹뷰 활성화시
 // if( location.host.match('ecommerce') || location.host.match('main$') ){
  document.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'visible') {
      clearTimeout(timeout);
      timeout = setTimeout(() => {
        Ntm00002.Event.fireUserDefined("pvDetail", { act_type: "pageview" });
      }, 500);
    }
  });
//  }


  // 최초 진입


   if(document.readyState === 'interactive' || document.readyState === 'complete'){
     didInitialLoadFire = true;
     trackPageView('load');
   }else {
     window.addEventListener('load', () => {
     didInitialLoadFire = true;
     trackPageView('load');
     });
   }



  /*
  window.addEventListener('load', () => {
    didInitialLoadFire = true;
    trackPageView('load');
  });
  */
  // pushState 감지
  const originalPushState = history.pushState;
  history.pushState = function (...args) {
    const result = originalPushState.apply(this, args);
    setTimeout(() => {
      trackPageView('pushState');
    }, 0);
    return result;
  };

  // popstate 감지
  if (!window.__nthPVPopstateRegistered) {
    window.__nthPVPopstateRegistered = true;

    window.addEventListener('popstate', () => {
      let tries = 0;
      const maxTries = 10;
      const interval = setInterval(() => {
        const currentUrl = location.href;

        if (!shouldSkipTracking(currentUrl)) {
          trackPageView('popstate');
          clearInterval(interval);
        }else{
          lastTrackedUrl = currentUrl;
        }

        if (++tries >= maxTries) {
          clearInterval(interval);
        }
      }, 100);
    });
  }
}

