function func() {
    var rateYn = true; //true : 화면 비율, false : 스크롤 비율
    var scrollRateArr = [25, 50, 75, 99]; // 100는 99로 설정
    var el = document.querySelector('body'); // 전체 높이를 가져올 element 
    var docHeight = recalculateDocumentSize();
    var currentPercentage = 0;
    var previousPercentage = 0;
    var path = location.pathname;
    var scrollHeight = el.offsetHeight;
    var timeout;

    var observer = new MutationObserver(() => {
      var newScrollHeight = el.offsetHeight;
      if (newScrollHeight !== scrollHeight) {
        docHeight = recalculateDocumentSize();
        n_scroll();
        scrollHeight = newScrollHeight;
      }
    });

    function scrollListener(){
      window.addEventListener('scroll', n_scrollWrapper);
      observer.observe(document.body, {
        childList: true,
        subtree: true,
      });
    }

    scrollListener();

    //스크롤 이벤트가 발생할 때마다 갱신
    function n_scrollWrapper() {
      n_scroll();
    }

    // 스크롤 기준값 체크 및 발동하는 함수
    function n_scroll(e) {
      var scrollVal = rateYn ? document.documentElement.clientHeight + this.scrollY : this.scrollY;
      var docHeight = rateYn ? el.offsetHeight : el.offsetHeight - document.documentElement.clientHeight;
      var scrollPercentage = Math.round(scrollVal / docHeight * 100);
      var i = 0;
      // 기준값으로 설정한 스크롤 비율을 넘어서면 currentPercentage에 저장함
      while (scrollRateArr[i] <= scrollPercentage) {
        currentPercentage = scrollRateArr[i++];
      }
      if (scrollY > 0 && (previousPercentage !== currentPercentage) && (scrollPercentage >= 25)) {
        clearTimeout(timeout);
        timeout = currentPercentage !== 0 && currentPercentage > previousPercentage
          ? setTimeout(() => { 
            // console.log("DEBUG NTH >> SCROLL %: " + currentPercentage);
            Ntm00002.Event.fireUserDefined("scroll", { "scroll_rate": currentPercentage, "act_type": "scroll"});
            previousPercentage = currentPercentage;
          }, 500)
          : null;
      }
    }

    // 문서 크기를 재계산 하는 함수
    function recalculateDocumentSize() {
      var newDocHeight = el.offsetHeight;
      previousPercentage = 0;
      currentPercentage = 0;
      return newDocHeight;
    }
}

function func() {
  const path = location.pathname;
