  const containers = document.querySelectorAll(containerSelectors.join(','));
  var timeout;
  function watchdog(){
  if (containers.length > 0) {
    containers.forEach(container => {
      const observer = new MutationObserver((mutationsList) => {
        for (const mutation of mutationsList) {
          swipeElements.forEach((swipeElement) => {
            const found = document.querySelector(swipeElement.css);
            if (found && !attachedElements.has(found) && path.includes(swipeElement.pageid)) {
              detectSwipe(swipeElement, handleSwipeDirection);
              attachedElements.add(found); // 중복 방지
            }
          });
        }
      });

      observer.observe(container, {
        childList: true,
        subtree: true
      });
    });
  }

  // 뉴스 상세 항목
  function getNewsInfo(el) {
    const infoArr = [];

  }

  // 스와이프 감지 함수
  function detectSwipe(element, callback) {
    let touchstartX = 0;
    let touchendX = 0;

    const target = document.querySelector(element.css);
    if (!target) {
      return;
    }

    target.addEventListener('touchstart', (e) => {
      touchstartX = e.touches[0].clientX;
    }, { passive: true });

    target.addEventListener('touchend', (e) => {
      touchendX = e.changedTouches[0].clientX;
      handleSwipe();
    }, { passive: true });

    function handleSwipe() {
      const move = touchstartX - touchendX;
      let exh_name = '';
      let list_id = '';
      let list_name = '';
      let el_name = '';
      let el_order = '';
      let news_seq = '';
      let banner_id = '';
      let banner_order = '';
      let banner_url = '';
      let banner_type = '배너';
      let rcmd_kwd = '';
      let position = '';

      if (element.css) {
        const el = document.querySelector(element.css);

        if (el && element.isBanner && !element.varType) {
         let text = '';
         const txtEl = el.querySelector(element.class);
         text = txtEl ? txtEl.innerText : '';
         if (txtEl && txtEl.querySelector('h2')) text = txtEl.querySelector('h2').innerText;
         if (txtEl && txtEl.querySelector('img')) text = txtEl.querySelector('img').alt;
         exh_name = text;
        } else if (el && element.varType === 'news') {
          // 뉴스 상세 항목
          // list_id, list_name, el_name, el_order, news_seq
          const activeEl = el.querySelector('.swiper-slide-active');
          const aEl = activeEl && activeEl.querySelector('.news-list-item__hot-container, .main-news-slider__item');
          const match = aEl && aEl.href.match(/categoryId=(\d+)/);
          list_id = match && match[1];
          list_name = "핫이슈";
          const matchId = aEl && aEl.href.match(/\/news\/detail\/(\d+)/);
          news_seq = matchId ? matchId[1] : '';
          if (activeEl && (activeEl.closest('[data-news-seq]') || activeEl.querySelector('[data-news-seq]'))){
            news_seq = activeEl.closest('[data-news-seq]') ? activeEl.closest('[data-news-seq]').dataset.newsSeq : activeEl.querySelector('[data-news-seq]').dataset.newsSeq;
          }
          const title = activeEl && activeEl.querySelector('.news-list-item__hot-container-title');
          el_name = title && title.innerText;
          if (!el_name && activeEl && activeEl.querySelector('a > img') ){
            el_name = activeEl.querySelector('a > img').alt;
          }
          const MenuItem = activeEl.matches('.swiper-slide') ? activeEl : activeEl.closest('.swiper-slide');
          if (MenuItem) {
            if (MenuItem.closest('.main-news-slider')) list_name = "뉴스 상단 슬라이드";

            const wrapper = MenuItem.closest('.news-list__hot, .main-news-slider');

            if (!wrapper) return '';
            if ( MenuItem.matches('[data-swiper-slide-index]')){
                el_order = Math.floor(MenuItem.dataset.swiperSlideIndex) + 1;
            }else{
              const items = Array.from(wrapper.querySelectorAll('.swiper-slide'));
              el_order = items.indexOf(MenuItem) + 1;
            }
          }
        } else if (el && element.varType === 'main') {
          // 라운드 메인 배너
          // banner_position, banner_id, banner_order, banner_url, rcmd_kwd
          const activeEl = el.querySelector('.swiper-slide-active');
          banner_id = activeEl ? activeEl.dataset.seq : '';
          banner_url = activeEl ? activeEl.dataset.value : '';
          banner_order = activeEl ? activeEl.dataset.swiperSlideIndex : '';
          position = element.position;

          const inputEl = document.querySelector('.search-input__input');
          rcmd_kwd = inputEl ? inputEl.value : '';
        } else if (el) {
          // 라운드 메인 배너
          // banner_position, banner_id, banner_order, banner_url, rcmd_kwd
          const activeEl = el.querySelector('.swiper-slide-active');
          if (activeEl ){
            banner_id = activeEl.dataset.seq ? activeEl.dataset.seq : activeEl.querySelector('[data-banner-id]') ? activeEl.querySelector('[data-banner-id]').dataset.bannerId  : '';
            banner_url = activeEl.dataset.value ? activeEl.dataset.value : activeEl.querySelector('[href]') ? activeEl.querySelector('[href]').href : '';
            banner_order = activeEl.dataset.swiperSlideIndex ? activeEl.dataset.swiperSlideIndex : '';
            position = element.position;

          const inputEl = document.querySelector('.search-input__input');
          rcmd_kwd = inputEl ? inputEl.value : '';
          }
        }
      }

      if (touchendX < touchstartX && move > moveRate) {
        callback('left', element.area, exh_name, list_id, list_name, el_name, el_order, news_seq, position, banner_id, banner_url, banner_order, rcmd_kwd, banner_type);
      } else if (touchendX > touchstartX && move < -moveRate) {
        callback('right', element.area, exh_name, list_id, list_name, el_name, el_order, news_seq, position, banner_id, banner_url, banner_order, rcmd_kwd, banner_type);
      }
    }
  }

  // 스와이프 커스텀 함수 호출
  function handleSwipeDirection(direction, area, exh_name, list_id, list_name, el_name, el_order, news_seq, position, banner_id, banner_url, banner_order, rcmd_kwd, banner_type) {
    Ntm00002.Event.fireUserDefined("swipe", {
