  }
  swipeElements.forEach((swipeElement) => {
    if(location.pathname === swipeElement.pageid){
            const found = document.querySelector(swipeElement.css);
            if (found && !attachedElements.has(found) && path.includes(swipeElement.pageid)) {
              detectSwipe(swipeElement, handleSwipeDirection);
              attachedElements.add(found); // 중복 방지
            }
    }
  });
  }
  watchdog();
  const newobserver = new MutationObserver((mutations) => {
    if (location.pathname.match('news$')){
    mutations.forEach((mutation) => {
        mutation.addedNodes.forEach((node) => {
            if (node.nodeType === 1 && node.matches('.news-list__category-group-item')){
            clearTimeout(timeout);
            timeout = setTimeout(() => {
                watchdog();
            }, 500);
            }
        });
    });
    }
  });
  newobserver.observe(document.body, {
      childList: true,
      subtree: true
  });
}

