  // 노출되는 화면 크기 수동 체크
  function isActuallyVisible(el, threshold) {
    const rect = el.getBoundingClientRect();
    const visibleHeight = Math.min(rect.bottom, window.innerHeight) - Math.max(rect.top, 0);
    const visibleRatio = visibleHeight / rect.height;
    return visibleRatio >= threshold;
  }

  // imElements.forEach(function (e, i) {
  //   waitForElement(e.css, () => observeTargets(e));
  // });

  // main 영역
  function watchDog(){
  waitForElement('section.custom-module', () => {
    document.querySelectorAll('section.custom-module').forEach(section => {
      const moduleType = section.getAttribute('data-module-type');
      const dataId = section.getAttribute('data-id');
      const modulePos = section.getAttribute('data-module-position');

      const cssSelector = `section[data-module-type="${moduleType}"][data-id="${dataId}"][data-module-position="${modulePos}"]`;

      const title = section.querySelector('h2');
      const text = title ? title.innerText : '';

      observeTargets({
        nth_pageId: '/main/home',
        css: cssSelector,
        nth_areaNo: modulePos,
        nth_areaNm: text,
        nth_areaType: moduleType
      });
    });
  });

  // 타임딜
  waitForElement('.timedeal', () => {
    document.querySelectorAll('.timedeal').forEach(section => {
      const title = section.querySelector('.custom-module__header> h2');
      const text = title ? title.innerText : '';
      const modulePos = section.querySelector('[data-timedeal-index]') ? Math.floor(section.querySelector('[data-timedeal-index]').dataset.timedealIndex) + 1 : '';
      observeTargets({
        nth_pageId: location.pathname,
        css: '.timedeal',
        nth_areaNm: text,
        nth_areaNo: modulePos
      });
    });
  });

  // 랭킹 키워드
  waitForElement('section.ranking-keyword', () => {
    const title = document.querySelector('section > div.ranking-keyword__top > h2');
    const text = title ? title.innerText : '';
    observeTargets({
      nth_pageId: '/main/ranking',
      css: 'section.ranking-keyword',
      nth_areaNm: text
    });
  });

  // 랭킹 카테고리 - 최초 로딩된 영역 감지
  waitForElement('div.ranking__category', () => {
    observeTargets({
      nth_pageId: '/main/ranking',
      css: 'div.ranking__category',
      nth_areaNm: '카테고리'
    }, 0.1); // 낮은 threshold
  });
  }

  // 무한 스크롤 추가 영역 자동 감지 등록
  const infiniteObserver = new MutationObserver((mutations) => {
    mutations.forEach(m => {
      [...m.addedNodes].forEach(n => {
        if (n.nodeType === 1 && n.matches && n.matches('div.ranking__category')) {
          // console.log('NTH TEST >> 무한스크롤 카테고리 추가 감지됨');
          observeTargets({
            nth_pageId: '/main/ranking',
            css: 'div.ranking__category',
            nth_areaNm: '카테고리'
          }, 0.1);
        }
      });
    });
  });
  infiniteObserver.observe(document.body, { childList: true, subtree: true });

  function observeTargets(e, threshold = impressionRate) {
    const targets = document.querySelectorAll(e.css);

    if (targets.length === 0) {
      // console.log(`NTH TEST >> 감지 대상 없음: ${e.css}`);
      return;
    }

    // console.log(`NTH TEST >> 감지 대상 ${targets.length}개 발견: ${e.css}`);

    const shouldObserve = (e.nth_pageId === '' || location.pathname === e.nth_pageId || location.pathname.match('sub/sub_main_a'));
    if (!shouldObserve) {
      // console.log(`NTH TEST >> 페이지 경로 불일치: 현재(${location.pathname}) vs 기대(${e.nth_pageId})`);
    }

    const io = new IntersectionObserver((entries, observer) => {
      for (const entry of entries) {
        if (entry.isIntersecting && isActuallyVisible(entry.target, threshold)) {
          if (entry.target.dataset.impressed === 'true') return;
          entry.target.dataset.impressed = 'true';

          const elTitle = entry.target.querySelector('.custom-module__header h2');
          const title = elTitle ? elTitle.innerText.replace(/\s+/g, ' ').trim() : '';

          // console.log('NTH TEST >> 노출 감지됨:', {
          //   nth_areaNm: title,
          //   nth_areaType: e.nth_areaType,
          //   nth_areaNo: e.nth_areaNo
          // });

          Ntm00002.Event.fireUserDefined("Scroll_Impression", {
            area_name: title || e.nth_areaNm,
            area_type: e.nth_areaType,
            area_no: e.nth_areaNo,
            act_type: 'scroll'
          });

         !reimpression && observer.unobserve(entry.target);
        }
      }
    }, {
      threshold
    });

    targets.forEach(el => {
      if (el.dataset.observed === 'true') return;
      if (shouldObserve) {
        // console.log(`NTH TEST >> observer 등록됨:`, el);
        io.observe(el);
      }
      el.dataset.observed = 'true';
    });
  }

  function waitForElement(selector, callback) {
    if (document.querySelector(selector)) {
      callback();
      return;
    }
    const observer = new MutationObserver(() => {
      if (document.querySelector(selector)) {
        observer.disconnect();
        callback();
      }
    });
    observer.observe(document.body, { childList: true, subtree: true });
  }
  watchDog();
  var newobserver = new MutationObserver(function(mutationList, ob){
    for(var mutation of mutationList){
      mutation.addedNodes.forEach(function (node) {
          if (node.nodeType === Node.ELEMENT_NODE && (node.matches('.custom-module, .timedeal'))){
            clearTimeout(timeout);
            timeout = setTimeout(() => {
              watchDog();
            }, 500);
          }
      });
    }
  });
  newobserver.observe(document.body, {childList: true, subtree: true}); 
}

function func() {
  var reimpression = true; // true: 노출마다 감지, false: 최초 1회만 감지
  var impressionRate = 0.7; // 화면 노출 비율
  const imElements = {{AL_impression}};

  console.log('NTH TEST >> impression detect start');

  function nth_replace(tmp) {
    tmp = tmp.replace(/\s\s+/g, " ");
    tmp = tmp.replace(/&gt;/g, '');
    tmp = tmp.replace(/\n|\t/g, " ").trim();
    if (tmp && tmp.length > 100) {
      tmp = tmp.substring(0, 97) + '...';
    }
    return tmp;
  }

  // ✅ auto 여부에 따라 title 처리 방식 분기
  function imTitle(el, isAuto) {
    if (isAuto) {
      const slides = el.querySelectorAll('.swiper-slide');
      const titles = [];
      var title = '';

      slides.forEach(slide => {
        let t = '';
        if (slide.querySelector('h2')) {
          t = slide.querySelector('h2').innerText;
        }else if (slide.closest('[data-value]')){
          t = slide.closest('[data-value]').dataset.value;
        }
        if (t) titles.push(nth_replace(t));
      });
      title = titles.join('___');
      return title;

    } else {
      title = el.innerText;
      if (el.querySelector('img')) title = el.querySelector('img').alt;
      if (el.querySelector('h2')) title = el.querySelector('h2').innerText;
      return nth_replace(title);
    }
  }

  function imUrl(el, isAuto) {
    if (isAuto) {
      let slides = el.querySelectorAll('.swiper-slide');
      if (slides.length === 0) {
        slides = el.querySelectorAll('.top-banner__slide');
      }
      if (el.querySelector('[data-main-popup-url]')) {
        slides = el.querySelectorAll('[data-main-popup-url]');
      }
      if (el.querySelector('[data-landing-url]')) {
        slides = el.querySelectorAll('[data-landing-url]');
      }
      const urls = [];

      slides.forEach(slide => {
        let t = '';
        if (slide.matches('[data-main-popup-url]')) {
          t = slide.dataset.mainPopupUrl;
        } else if (slide.matches('[data-landing-url]')) {
          t = slide.dataset.landingUrl;
        } else if (slide.querySelector('a')) {
          t = slide.querySelector('a').href;
        } else if (slide.dataset) {
          t = slide.dataset.value;
        }
        if (t) urls.push(t);
      });
      return urls.join('___');
    } else {
      let url = '';
      if (el.querySelector('[data-landing-url]')){
        url = el.querySelector('[data-landing-url]').dataset.landingUrl;
      } else if (el.querySelector('a')) {
        url = el.querySelector('a').href;
      }
      return url;
    }
  }

  function imOrder(el) {
      const bannerSlideItem = el.closest('.top-banner__swiper, .event__item');
      if (bannerSlideItem) {
        const wrapper = bannerSlideItem.closest('.swiper-wrapper, .event__list');
        if (!wrapper) return '';
        const items = Array.from(wrapper.querySelectorAll('.top-banner__slide, .event__item'));
        const index = items.indexOf(bannerSlideItem) + 1;
        return index;
      }
  }
  function imbOrder(el, isAuto) {
      if (isAuto) {
        const slides = el.querySelectorAll('.top-banner__slide, [data-swiper-slide-index]');
        const kwds = [];

        slides.forEach(slide => {
          let t = '';
          if (slide.dataset) {
            t = slide.dataset.swiperSlideIndex;
            if (t){
              t = Math.floor(t) + 1;
            }
          } 
          if (t) kwds.push(t);
        });
        return kwds.join('___');
      } else {
        // 수동 롤링 배너의 banner_order 있는 경우 해당 로직 변경
        return '';
      }
  }
  function imbId(el, isAuto) {
    if (isAuto) {
      let slides = el.querySelectorAll('.banner_id');

      if (el.dataset.id === 'mainpop'){
        return el.dataset.mainpopId;
      } else{
        if (slides.length === 0) {
          slides = el.querySelectorAll('.top-banner__slide');
        }
        if (slides.length === 0) {
          slides = el.querySelectorAll('[data-main-popup-id]');
        }
        if (slides.length === 0) {
          slides = el.querySelectorAll('[data-ranking-bannder-id]');
        }
      }
      const ids = [];
      slides.forEach(slide => {
        let t = '';
        if (slide.dataset) {
          t = slide.dataset.bannerId || slide.dataset.seq || slide.dataset.mainPopupId || slide.dataset.rankingBannderId;
        } 
        if (t) ids.push(t);
      });
      return ids.join('___');
    } else {
      let bid = '';
      if (el.querySelector('.banner_id')) {
        bid = el.querySelector('.banner_id').dataset.bannerId; 
      } 
      else if (el.dataset.commbarId){
        bid = el.dataset.commbarId;
       }
      return bid;
    }
  }
  function imeId(el, isAuto) {
    if (isAuto) {
      const slides = el.querySelectorAll('.event__item');
      const ids = [];

      slides.forEach(slide => {
        let t = '';
        if (slide.dataset) {
          t = slide.dataset.eventId;
        } 
        if (t) ids.push(t);
      });
      return ids.join('___');
    } else {
      let eid = '';
      if (el.querySelector('.event__item')) eid = el.querySelector('.event__item').dataset.eventId;
      if (el.closest('.event__item')) eid = el.closest('.event__item').dataset.eventId;
      return eid;
    }
  }
  function imKwd(el, isAuto) {
    if (isAuto) {
      const slides = el.querySelectorAll('.top-banner__slide');
      const kwds = [];

      slides.forEach(slide => {
        let t = '';
        if (slide.dataset) {
          t = slide.dataset.displaySearchKeyword;
        } 
        if (t) kwds.push(t);
      });
      return kwds.join('___');
    } else {
      let kwd = '';
      // 단일값 필요한 요소 있을 시 작성 필요
      return kwd;
    }
  }

// 추가 부분
function imDataId(el, isAuto) {
  if (isAuto) {
      let slides = el.querySelectorAll('.rolling-banner__item');
      if (el.querySelector('[data-id="ad-rolling-banner-nestads-ad"]')) {
        slides = el.querySelectorAll('[data-id="ad-rolling-banner-nestads-ad"]');
      }
      const dataids = [];

      slides.forEach(slide => {
        let t = '';
        if (slide.dataset) {
          t = slide.dataset.id;
        } 
        if (t) dataids.push(t);
      });
      return dataids.join('___');
  } else {
    let dataId = '';
    if (el.dataset.id) {
      dataId = el.dataset.id;
    }
    return dataId;
  }
}

  const elementMeta = new Map();         // element → imElement 설정 (auto 포함)
  const alreadyObserved = new Set();     // 중복 방지

  const io = new IntersectionObserver((entries) => {
    for (const entry of entries) {
      if (entry.isIntersecting) {
        const config = elementMeta.get(entry.target);
        const bname = imTitle(entry.target, config? config.auto : false);
        const url = imUrl(entry.target, config? config.auto : false);
        const order = imOrder(entry.target);
        let bid = imbId(entry.target, config? config.auto : false);
        let eid = imeId(entry.target, config? config.auto : false);
        let bannertype = entry.target.closest('.commerce-popup__swiper') ? '팝업 배너' : '배너';
        let did = imDataId(entry.target, config? config.auto : false);    // 추가 부분
        let rcmd_kwd = imKwd(entry.target, config? config.auto : false);
        const banner_order = imbOrder(entry.target, config? config.auto: false);

        Ntm00002.Event.fireUserDefined("impression", {
          act_type: 'impression',
          exh_name: bname,
          exh_url: url,
          order: order,
          banner_order: banner_order,
          impression_type: config.impression_type,
          banner_position : config.position,
          banner_id : bid,
          event_id : eid,
          banner_type : bannertype,
          data_id: did,  // 추가 부분
          rcmd_kwd: rcmd_kwd
        });

        if (!reimpression) {
          io.unobserve(entry.target);
        }
      }
    }
  }, { threshold: impressionRate });

  // 초기 DOM 요소에 대해 감지 등록
  imElements.forEach(e => {
    if (location.pathname === e.page_id) {
      try {
        const targets = document.querySelectorAll(e.css);
        targets.forEach(el => {
          if (el.classList.contains('is-end')) return;
          if (!alreadyObserved.has(el)) {
            elementMeta.set(el, e);
            io.observe(el);
            console.log('NTH TEST >> impression detect 1:', e.css, el);
            alreadyObserved.add(el);
          }
        });
      } catch (err) {
        // console.warn('NTH TEST >> Initial selector error:', e.css, err);
      }
    }
  });

  // DOM 생성 감지용 MutationObserver
  const body = document.querySelector("body");
  const newobserver = new MutationObserver(function (mutationList) {
    for (const mutation of mutationList) {
      mutation.addedNodes.forEach(function (node) {
        if (node.nodeType === Node.ELEMENT_NODE) {
          imElements.forEach(function (e) {
            if (location.pathname === e.page_id) {
              let targets = [];

              try {
                if (typeof node.matches === 'function' && node.matches(e.css)) {
                  targets = [node];
                } else if (typeof node.querySelectorAll === 'function') {
                  targets = Array.from(node.querySelectorAll(e.css));
                }

                targets.forEach(el => {
                  if (!alreadyObserved.has(el)) {
                    elementMeta.set(el, e);
                    io.observe(el);
                    console.log('NTH TEST >> impression detect 2:', e.css, el);
                    alreadyObserved.add(el);
                  }
                });
              } catch (err) {
                // console.warn('NTH TEST >> Selector error in mutation observer:', e.css, err);
              }
            }
          });
        }
      });
    }
  });

  newobserver.observe(body, { childList: true, subtree: true });
  // window.onload = func;
}

